INSERT INTO `app` VALUES (393219349504102400,'创建一个个体的团队介绍静态网站。色系：活力橙蓝(#0277b','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/22/b7782daf5097452e9712cc8613d329cc.jpg','创建一个个体的团队介绍静态网站。色系：活力橙蓝(#0277bd+#ff6f00)，布局：网格卡片。包含团队愿景Banner、成员卡片网格（含头像占位、姓名、职位、简介）、团队文化价值观、团队数据展示（成员数量、项目经验等）、加入我们招聘区、联系方式。页面需有成员卡片悬浮和滚动渐入动效。所有内容使用真实可信的团队场景文本。\n\n网站需要展示的具体内容：添加模拟数据即可。','multi_file','tysYeIbX','2026-03-22 14:58:50',99,390705603766513664,'2026-03-22 16:33:51','2026-03-22 14:54:18','2026-03-22 16:33:51',0),(393221828492955648,'创建一个个体的在线个人简历静态网站。色系：商务蓝(#1565','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/22/6e609cc9cdd24e9e8381d2b0b8dc84db.jpg','创建一个个体的在线个人简历静态网站。色系：商务蓝(#1565c0+#e3f2fd)，布局：单栏居中。包含个人照片与基本信息区、工作经历时间线、教育背景、技能评分条（纯CSS动效）、项目经验卡片、联系方式区域。页面需有滚动渐入和进度条加载动效。所有内容使用真实可信的示例文本。\n网站需要展示的具体内容：添加模拟数据即可。','single_html','Y3PowI3s','2026-03-22 15:11:44',99,390705603766513664,'2026-03-22 16:33:50','2026-03-22 15:04:09','2026-03-22 16:33:50',0),(393222100686508032,'创建一个个体的活动宣传静态网站。色系：活力橙红(#e6510','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/22/6b05eb5b7cec4d55b34f8422110464f0.jpg','创建一个个体的活动宣传静态网站。色系：活力橙红(#e65100+#fff3e0)，布局：全屏模块滚动。包含活动主题全屏Banner、活动倒计时器（纯JS实现实时倒计时）、活动日程时间表、嘉宾/组织者介绍卡片、往期活动数据回顾（参与人数等数字动效）、报名表单（仅UI无后端）。请为活动设计一个主题 LOGO。页面需有倒计时翻牌和模块渐入动效。所有内容使用真实可信的活动场景文本。\n\n网站需要展示的具体内容：活动主题是山东天泽公司春游活动通知页，数据模拟即可。\n\n基于VUE。','vue_project','RzsM2grt','2026-03-22 15:11:48',99,390705603766513664,'2026-03-22 16:33:52','2026-03-22 15:05:14','2026-03-22 16:33:51',0);
