           font-family: \'Segoe UI\', \'Microsoft YaHei\', sans-serif;\n            line-height: 1.6;\n            color: var(--text-dark);\n            background-color: var(--white);\n            overflow-x: hidden;\n        }\n\n        #progress-bar {\n            height: 4px;\n            background: var(--primary-color);\n            position: fixed;\n            top: 0;\n            left: 0;\n            width: 0%;\n            z-index: 9999;\n            transition: width 0.3s ease;\n        }\n\n        .container {\n            max-width: 1200px;\n            margin: 0 auto;\n            padding: 0 20px;\n        }\n\n        /* Header Styles */\n        .header {\n            background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));\n            color: var(--white);\n            padding: 80px 0 60px;\n            text-align: center;\n            position: relative;\n            overflow: hidden;\n        }\n\n        .header::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            bottom: 0;\n            background-image: url(\'https://img1.baidu.com/it/u=3441977137,873658132&fm=253&fmt=auto&app=138&f=JPEG?w=681&h=500\');\n            background-size: cover;\n            background-position: center;\n            opacity: 0.1;\n            z-index: 1;\n        }\n\n        .header-content {\n            position: relative;\n            z-index: 2;\n        }\n\n        .profile-img {\n            width: 150px;\n            height: 150px;\n            border-radius: 50%;\n            border: 4px solid var(--white);\n            object-fit: cover;\n            margin: 0 auto 20px;\n            box-shadow: var(--shadow);\n        }\n\n        .header__title {\n            font-size: 2.5rem;\n            margin-bottom: 10px;\n            font-weight: bold;\n        }\n\n        .header__subtitle {\n            font-size: 1.2rem;\n            margin-bottom: 20px;\n            opacity: 0.9;\n        }\n\n        .header__description {\n            font-size: 1rem;\n            max-width: 600px;\n            margin: 0 auto 30px;\n            opacity: 0.8;\n        }\n\n        .contact-info {\n            display: flex;\n            justify-content: center;\n            flex-wrap: wrap;\n            gap: 20px;\n            margin-bottom: 20px;\n        }\n\n        .contact-item {\n            display: flex;\n            align-items: center;\n            gap: 5px;\n            font-size: 0.9rem;\n        }\n\n        .social-links {\n            display: flex;\n            justify-content: center;\n            gap: 15px;\n        }\n\n        .social-link {\n            display: inline-flex;\n            align-items: center;\n            justify-content: center;\n            width: 40px;\n            height: 40px;\n            border-radius: 50%;\n            background: rgba(255, 255, 255, 0.2);\n            color: var(--white);\n            text-decoration: none;\n            transition: var(--transition);\n        }\n\n        .social-link:hover {\n            background: var(--white);\n            color: var(--primary-color);\n            transform: translateY(-2px);\n        }\n\n        /* Section Styles */\n        .section {\n            padding: 80px 0;\n            background-color: var(--white);\n        }\n\n        .section--light {\n            background-color: var(--primary-light);\n        }\n\n        .section-title {\n            text-align: center;\n            font-size: 2rem;\n            color: var(--primary-color);\n            margin-bottom: 50px;\n            position: relative;\n        }\n\n        .section-title::after {\n            content: \'\';\n            position: absolute;\n            bottom: -10px;\n            left: 50%;\n            transform: translateX(-50%);\n            width: 60px;\n            height: 3px;\n            background: var(--primary-color);\n        