INSERT INTO `prompt_template` VALUES (1,'API文档展示页','merchant','互联网/IT','开发者API接口文档与示例展示','为一位{{identity}}互联网/IT商户创建API文档展示静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含API概览介绍、接口列表导航（按模块分类）、请求/响应示例代码块（支持语法高亮）、参数说明表格、错误码对照表、快速开始指南。{{logoOption}}页面需有代码块复制按钮和侧边栏锚点导航。所有示例使用真实可信的API场景数据。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"开发者暗色(#1e1e1e+#569cd6)\",\"GitHub风(#fff+#24292e)\",\"技术蓝(#0d47a1+#e3f2fd)\"],\"defaultValue\":\"开发者暗色(#1e1e1e+#569cd6)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"左侧导航+右侧内容\",\"顶部导航+内容\",\"三栏布局\"],\"defaultValue\":\"左侧导航+右侧内容\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为API品牌设计一个SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"商户\"}]',4,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(2,'培训机构招生页','merchant','教育/培训','培训机构课程招生与报名引导页','为一位{{identity}}教育/培训商户创建招生宣传静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含课程亮点Banner、课程大纲时间表、师资力量介绍、学员成果展示（就业数据、薪资涨幅等数字动效）、优惠活动倒计时、在线咨询表单（仅UI）。{{logoOption}}页面需有倒计时和数据滚动动效。所有内容使用真实可信的培训场景文本。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"活力橙(#e65100+#fff3e0)\",\"学术蓝(#1a237e+#e8eaf6)\",\"清新绿(#2e7d32+#e8f5e9)\"],\"defaultValue\":\"活力橙(#e65100+#fff3e0)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"单页滚动\",\"模块卡片\",\"左右分栏\"],\"defaultValue\":\"单页滚动\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为培训机构设计一个SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"商户\"}]',3,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(3,'个人二手市集','individual','电商/零售','个人闲置物品展示与交易信息页','为一位{{identity}}电商/零售个体创建二手市集静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含物品分类导航、商品卡片网格（含图片占位、价格、成色标签）、卖家信用评分展示、交易须知说明、联系方式区域。{{logoOption}}页面需有商品筛选和卡片悬浮动效。所有商品使用真实可信的二手物品示例。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"温馨黄(#fff8e1+#f57f17)\",\"清新蓝(#e1f5fe+#0277bd)\",\"简约灰白(#fafafa+#616161)\"],\"defaultValue\":\"温馨黄(#fff8e1+#f57f17)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"网格瀑布流\",\"列表详情\",\"分类+商品\"],\"defaultValue\":\"网格瀑布流\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":false,\"trueText\":\"请设计一个二手市集SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"个体\"}]',3,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(4,'私人诊所介绍页','merchant','医疗/健康','私人诊所服务项目与医生介绍页','为一位{{identity}}医疗/健康商户创建诊所介绍静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含诊所环境展示、服务项目卡片（含价格区间）、医生资质与擅长领域、预约流程说明、诊所数据（服务人次、满意度等）、地址与营业时间。{{logoOption}}页面需有滚动渐入和数据动效。所有内容使用真实可信的医疗场景文本。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"医疗蓝白(#e3f2fd+#1565c0)\",\"温馨绿(#e8f5e9+#388e3c)\",\"洁净白(#fff+#42a5f5)\"],\"defaultValue\":\"医疗蓝白(#e3f2fd+#1565c0)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"单页滚动\",\"模块分区\",\"左图右文\"],\"defaultValue\":\"单页滚动\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为诊所设计一个医疗主题SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"商户\"}]',3,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(5,'美食博主主页','individual','餐饮/美食','美食博主探店记录与推荐分享页','为一位{{identity}}餐饮/美食博主创建探店分享静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含博主介绍Banner、探店文章卡片列表（含餐厅名、评分、美食图片占位）、美食分类标签筛选、城市地图标记、粉丝数据展示（探店数量、粉丝量等）。{{logoOption}}页面需有卡片悬浮和图片懒加载动效。所有内容使用真实可信的美食场景文本。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"食欲红(#c62828+#ffebee)\",\"温暖橙(#e65100+#fff3e0)\",\"清新绿白(#fff+#66bb6a)\"],\"defaultValue\":\"食欲红(#c62828+#ffebee)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"卡片瀑布流\",\"时间线列表\",\"网格画廊\"],\"defaultValue\":\"卡片瀑布流\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为博主设计一个美食主题SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"个体\"}]',2,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(6,'连锁餐饮品牌官网','enterprise','餐饮/美食','连锁餐饮企业品牌形象与门店展示','为一家{{identity}}餐饮/美食企业创建品牌官网静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含品牌故事全屏Banner、招牌菜品展示、门店分布地图、加盟政策介绍、企业数据量化（门店数、覆盖城市、年服务人次等数字动效）、新闻资讯列表。{{logoOption}}页面需有视差滚动和模块渐入动效。所有内容使用真实可信的餐饮品牌数据。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"品牌红金(#b71c1c+#ffd54f)\",\"自然绿棕(#33691e+#efebe9)\",\"高端黑白(#212121+#fff)\"],\"defaultValue\":\"品牌红金(#b71c1c+#ffd54f)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"全屏模块滚动\",\"经典企业布局\",\"杂志风排版\"],\"defaultValue\":\"全屏模块滚动\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为品牌设计一个企业级SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"企业\"}]',3,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(7,'个人理财规划展示','individual','金融/财务','个人财务目标与资产配置可视化页','为一位{{identity}}金融/财务个体创建理财规划静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含财务目标总览、资产配置饼图（纯CSS/SVG）、月度收支趋势图、投资组合卡片、理财知识笔记区、财务健康评分。{{logoOption}}页面需有数据加载和图表动效。所有数据使用真实可信的理财场景数值。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"金融蓝(#0d47a1+#e3f2fd)\",\"稳健绿(#1b5e20+#e8f5e9)\",\"专业灰(#37474f+#eceff1)\"],\"defaultValue\":\"金融蓝(#0d47a1+#e3f2fd)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"仪表盘网格\",\"卡片列表\",\"左侧导航+右侧内容\"],\"defaultValue\":\"仪表盘网格\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":false,\"trueText\":\"请设计一个理财主题SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"个体\"}]',2,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(8,'金融服务机构官网','merchant','金融/财务','金融服务商户产品介绍与客户案例页','为一位{{identity}}金融/财务商户创建服务展示静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含服务介绍Banner、产品方案卡片（含收益率、周期等）、客户案例成果展示、服务流程说明、资质认证展示、在线咨询表单（仅UI）。{{logoOption}}页面需有数据滚动和模块渐入动效。所有内容使用真实可信的金融场景数据。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"信任蓝(#1565c0+#e3f2fd)\",\"稳重灰金(#37474f+#ffd54f)\",\"专业黑白(#212121+#fafafa)\"],\"defaultValue\":\"信任蓝(#1565c0+#e3f2fd)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"单页滚动\",\"模块分区\",\"左右分栏\"],\"defaultValue\":\"单页滚动\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为金融机构设计一个专业SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"商户\"}]',3,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(9,'摄影工作室展示','merchant','设计/创意','摄影商户作品展示与服务套餐页','为一位{{identity}}设计/创意商户创建摄影工作室静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含工作室介绍、摄影作品画廊（按类型分类：婚纱、写真、商业等）、服务套餐价格表、摄影师团队介绍、客户评价轮播、预约表单（仅UI）。{{logoOption}}页面需有图片懒加载和画廊灯箱动效。所有作品使用纯色占位或渐变代替。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"极简黑白(#fff+#000)\",\"高级灰(#eceff1+#455a64)\",\"温暖米色(#faf8f5+#8d6e63)\"],\"defaultValue\":\"极简黑白(#fff+#000)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"网格画廊\",\"全屏滚动\",\"瀑布流\"],\"defaultValue\":\"网格画廊\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为工作室设计一个摄影主题SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"商户\"}]',2,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(10,'创意设计公司官网','enterprise','设计/创意','设计公司品牌形象与案例展示页','为一家{{identity}}设计/创意企业创建公司官网静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含公司理念全屏Banner、服务领域介绍（品牌设计、UI/UX、视觉传达等）、经典案例展示、团队介绍、客户LOGO墙、联系方式与地址。{{logoOption}}页面需有视差滚动和案例悬浮动效。所有案例使用纯色占位或CSS渐变。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"创意多彩(#f5f5f5+渐变强调色)\",\"极简黑白(#fff+#000)\",\"现代蓝(#0d47a1+#e3f2fd)\"],\"defaultValue\":\"创意多彩(#f5f5f5+渐变强调色)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"全屏模块滚动\",\"网格分区\",\"杂志风排版\"],\"defaultValue\":\"全屏模块滚动\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为设计公司设计一个创意SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"企业\"}]',3,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(11,'建筑设计师作品集','individual','房地产/建筑','建筑设计师项目作品展示页','为一位{{identity}}房地产/建筑设计师创建作品集静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含设计师简介、建筑项目画廊（含项目名称、类型、面积等信息）、设计理念阐述、获奖与认证、设计流程时间线。{{logoOption}}页面需有图片悬浮放大和滚动视差动效。所有项目图使用纯色占位或建筑剪影。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"建筑灰(#37474f+#eceff1)\",\"极简黑白(#fff+#212121)\",\"现代蓝灰(#455a64+#cfd8dc)\"],\"defaultValue\":\"建筑灰(#37474f+#eceff1)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"网格画廊\",\"全屏滚动\",\"瀑布流\"],\"defaultValue\":\"网格画廊\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请设计一个建筑师个人品牌SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"个体\"}]',2,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(12,'房产中介门店页','merchant','房地产/建筑','房产中介门店房源展示与经纪人介绍','为一位{{identity}}房地产/建筑商户创建中介门店静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含门店介绍、在售房源卡片（含价格、面积、户型、位置）、房源筛选标签、金牌经纪人介绍、成交数据展示（月成交量、客户满意度等）、联系方式。{{logoOption}}页面需有房源筛选和卡片悬浮动效。所有房源使用真实可信的示例数据。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"商务蓝(#1565c0+#e3f2fd)\",\"稳重灰(#616161+#f5f5f5)\",\"温暖橙(#e65100+#fff3e0)\"],\"defaultValue\":\"商务蓝(#1565c0+#e3f2fd)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"网格卡片\",\"列表详情\",\"左侧筛选+右侧房源\"],\"defaultValue\":\"网格卡片\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"